    let result = '';

    for (let i = 0; i < s.length; i++) {
        const char = s[i];

        if (char === '*') {
            // Remove the last character if it exists
            if (result.length > 0) {
                result = result.slice(0, -1);
            }
        } else if (char === '#') {
            // Append a copy of the current result to itself
            result += result;
        } else if (char === '%') {
            // Reverse the current result
            result = result.split('').reverse().join('');
